// Готовим тело запроса к резервной модели Groq (chat completions).
let transcript = '';
try { transcript = $('OpenAI Transcribe (Whisper)').item.json.text || ''; } catch (e) {}
if (!transcript) { try { transcript = $('Groq Transcribe (Fallback)').item.json.text || ''; } catch (e) {} }
if (!transcript) { throw new Error('Нет транскрипта для резервного ИИ-шага.'); }
const SYSTEM = "Ты — ассистент, который ведёт деловой дневник собственника компании. Получив расшифровку голосовой записи за день (итоги дня, инсайты, проблемы), верни СТРОГО валидный JSON без markdown, без пояснений, ровно с такими полями:
{
  "Заголовок": "",
  "Итоги": [],
  "Инсайты": [],
  "Проблемы": [],
  "Следующие шаги": []
}

Правила:
- Заголовок: одна короткая строка (до 80 символов), суть дня.
- Итоги / Инсайты / Проблемы / Следующие шаги: массивы коротких пунктов на русском.
- Если по какому-то полю в записи ничего нет — верни пустой массив [].
- Не выдумывай факты, которых нет в записи. Пиши по-русски, по-деловому, кратко.";
return { json: { model: 'llama-3.3-70b-versatile', temperature: 0.2, response_format: { type: 'json_object' }, messages: [ { role: 'system', content: SYSTEM }, { role: 'user', content: transcript } ] } };

// Собираем payload для Apps Script Web App.
// 1) Берём расшифровку и структурированное summary.
// 2) Считаем дату в нужной таймзоне (по умолчанию Europe/Warsaw).

const TZ = 'Europe/Warsaw'; // должна совпадать с TIMEZONE в Apps Script

const raw = $json.choices?.[0]?.message?.content ?? $json.message?.content ?? $json.content ?? $json.output ?? $json.text ?? $json;
let s;
if (typeof raw === 'string') {
  try { s = JSON.parse(raw); }
  catch (e) {
    const m = raw.match(/\{[\s\S]*\}/);
    if (!m) throw new Error('OpenAI did not return JSON: ' + raw);
    s = JSON.parse(m[0]);
  }
} else { s = raw; }

const summary = {
  'Заголовок': s['Заголовок'] ?? '',
  'Итоги': Array.isArray(s['Итоги']) ? s['Итоги'] : [],
  'Инсайты': Array.isArray(s['Инсайты']) ? s['Инсайты'] : [],
  'Проблемы': Array.isArray(s['Проблемы']) ? s['Проблемы'] : [],
  'Следующие шаги': Array.isArray(s['Следующие шаги']) ? s['Следующие шаги'] : []
};

// Дата записи в локальной таймзоне -> YYYY-MM-DD
const now = new Date();
const fmt = new Intl.DateTimeFormat('en-CA', {
  timeZone: TZ, year: 'numeric', month: '2-digit', day: '2-digit'
});
const date = fmt.format(now); // YYYY-MM-DD

// Транскрипт мог прийти от основного Whisper или от резервного Groq.
let transcript = '';
try { transcript = $('OpenAI Transcribe (Whisper)').item.json.text || ''; } catch (e) {}
if (!transcript) { try { transcript = $('Groq Transcribe (Fallback)').item.json.text || ''; } catch (e) {} }
const chatId = $('Telegram Trigger (Voice)').item.json.message.chat.id;

return {
  json: {
    token: 'REPLACE_SHARED_TOKEN', // должен совпадать с DIARY_TOKEN в Script Properties
    date,
    transcript,
    summary,
    chatId
  }
};

